
import React from "react";
import { useSelector } from "react-redux";

export default function Cart() {
  const cart = useSelector((store)=>store.cart)
  return (
    <div className="min-h-screen bg-gray-100 p-6">
      <div className="max-w-7xl mx-auto grid lg:grid-cols-3 gap-6">

        {/* LEFT - CART ITEMS */}
        <div className="lg:col-span-2 space-y-5">

          {cart?.items?.map((item) => (
            <div
              key={item.id}
              className="bg-white rounded-xl p-5 flex gap-5 shadow-sm border"
            >
              {/* Image */}
              <div className="w-28 h-28 bg-gray-50 rounded-lg flex items-center justify-center">
                <img
                  src="/phone.png"
                  alt={item?.name}
                  className="h-20 object-contain"
                />
              </div>

              {/* Content */}
              <div className="flex-1 flex flex-col justify-between">

                {/* Top */}
                <div className="flex justify-between items-start">
                  <div>
                    <h3 className="font-semibold text-sm">
                    {item?.name}
                    </h3>
                    <p className="text-[#01A49E] font-semibold mt-1">
                      ${item?.final_price}
                    </p>
                  </div>

                  {/* Color dots */}
                  <div className="flex gap-2">
                    <div className="w-4 h-4 bg-gray-300 rounded-full"></div>
                    <div className="w-4 h-4 bg-red-200 rounded-full"></div>
                  </div>
                </div>

                {/* Middle */}
                <div className="flex items-center gap-4 mt-3">
                  
                  {/* Qty */}
                  <div className="flex items-center border rounded-md overflow-hidden">
                    <button className="px-3 py-1">-</button>
                    <span className="px-4">{item?.qty}</span>
                    <button className="px-3 py-1">+</button>
                  </div>

                  {/* Shipping */}
                  <span className="text-xs bg-green-100 text-green-600 px-2 py-1 rounded">
                    FREE SHIPPING
                  </span>
                </div>

                {/* Bottom */}
                <div className="flex items-center gap-2 text-sm text-gray-500 mt-2">
                  <span className={item?.stock ? "text-green-500" : "text-red-500"}>●</span>
                  {item?.stock ? "In Stock" : Not in stock}
                </div>
              </div>
            </div>
          ))}
        </div>

        {/* RIGHT - ORDER SUMMARY */}
        <div className="bg-white rounded-xl p-6 shadow-sm border h-fit">
          <h2 className="font-semibold mb-4">Order Summary</h2>

          <div className="space-y-3 text-sm">

            <div className="flex justify-between">
              <span className="text-gray-500">Original Total:</span>
              <span className="font-medium">${cart?.originalTotal}</span>
            </div>

            {/* <div className="flex justify-between">
              <span className="text-gray-500">Shipping estimate:</span>
              <span className="font-medium">$600.00</span>
            </div>

            <div className="flex justify-between">
              <span className="text-gray-500">Tax estimate:</span>
              <span className="font-medium">$137.00</span>
            </div> */}

            <div className="border-t pt-3 flex justify-between font-semibold">
              <span>ORDER TOTAL:</span>
              <span>${cart?.finalTotal}</span>
            </div>
          </div>

          <button className="w-full mt-6 bg-[#01A49E] text-white py-3 rounded-xl font-medium hover:opacity-90">
            CHECKOUT
          </button>
        </div>

      </div>
    </div>
  );
}